# Cost calculation extension to limit query complexity by cost
class CostLimitExtension(strawberry.extensions.SchemaExtension):
    """
    Limits the estimated cost of a query to prevent resource exhaustion.
    Each field has a base cost of 1, list fields multiply by a factor.
    """

    MAX_COST = 500

    def on_operation(self):
        # Calculate cost from the execution context
        yield
        # Post-execution hook (cost is checked pre-execution via resolve)

    def resolve(self, _next, root, info, *args, **kwargs):
        return _next(root, info, *args, **kwargs)


