@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_seller(self, info: Info, input: CreateSellerInput) -> Seller:
        db: Session = info.context["db"]
        name = sanitize_string(input.name)
        email = validate_email(input.email)

        if not name:
            raise ValueError("Seller name cannot be empty")

        # Check for duplicate email
        existing = db.query(SellerModel).filter(SellerModel.email == email).first()
        if existing:
            raise ValueError("A seller with this email already exists")

        seller = SellerModel(name=name, email=email, rating=0.0)
        db.add(seller)
        db.commit()
        db.refresh(seller)
        return Seller(id=seller.id, name=seller.name, email=seller.email, rating=seller.rating)

    @strawberry.mutation
    def create_product(self, info: Info, input: CreateProductInput) -> Product:
        db: Session = info.context["db"]

        name = sanitize_string(input.name)
        if not name:
            raise ValueError("Product name cannot be empty")

        description = sanitize_string(input.description, max_length=2000) if input.description else None
        price = validate_price(input.price)
        seller_id = validate_positive_int(input.seller_id, "seller_id")

        # Verify seller exists
        seller = db.query(SellerModel).filter(SellerModel.id == seller_id).first()
        if not seller:
            raise ValueError(f"Seller with id {seller_id} not found")

        product = ProductModel(
            name=name,
            description=description,
            price=price,
            seller_id=seller_id,
        )

        # Add categories if provided
        if input.category_ids:
            for cat_id in input.category_ids:
                cat_id = validate_positive_int(cat_id, "category_id")
                category = db.query(CategoryModel).filter(CategoryModel.id == cat_id).first()
                if not category:
                    raise ValueError(f"Category with id {cat_id} not found")
                product.categories.append(category)

        db.add(product)
        db.commit()
        db.refresh(product)

        # Reload with relationships
        p = (
            db.query(ProductModel)
            .options(
                selectinload(ProductModel.seller),
                selectinload(ProductModel.reviews),
                selectinload(ProductModel.images),
                selectinload(ProductModel.categories),
            )
            .filter(ProductModel.id == product.id)
            .first()
        )
        return _product_model_to_type(p)

    @strawberry.mutation
    def create_review(self, info: Info, input: CreateReviewInput) -> Review:
        db: Session = info.context["db"]

        product_id = validate_positive_int(input.product_id, "product_id")
        reviewer_name = sanitize_string(input.reviewer_name)
        rating = validate_rating(input.rating)
        comment = sanitize_string(input.comment, max_length=2000) if input.comment else None

        if not reviewer_name:
            raise ValueError("Reviewer name cannot be empty")

        # Verify product exists
        product = db.query(ProductModel).filter(ProductModel.id == product_id).first()
        if not product:
            raise ValueError(f"Product with id {product_id} not found")

        review = ReviewModel(
            product_id=product_id,
            reviewer_name=reviewer_name,
            rating=rating,
            comment=comment,
        )
        db.add(review)
        db.commit()
        db.refresh(review)
        return Review(
            id=review.id,
            product_id=review.product_id,
            reviewer_name=review.reviewer_name,
            rating=review.rating,
            comment=review.comment,
        )

    @strawberry.mutation
    def add_image(self, info: Info, input: AddImageInput) -> Image:
        db: Session = info.context["db"]

        product_id = validate_positive_int(input.product_id, "product_id")
        url = validate_url(input.url)
        alt_text = sanitize_string(input.alt_text) if input.alt_text else None

        # Verify product exists
        product = db.query(ProductModel).filter(ProductModel.id == product_id).first()
        if not product:
            raise ValueError(f"Product with id {product_id} not found")

        image = ImageModel(
            product_id=product_id,
            url=url,
            alt_text=alt_text,
        )
        db.add(image)
        db.commit()
        db.refresh(image)
        return Image(
            id=image.id,
            product_id=image.product_id,
            url=image.url,
            alt_text=image.alt_text,
        )

    @strawberry.mutation
    def create_category(self, info: Info, input: CreateCategoryInput) -> Category:
        db: Session = info.context["db"]

        name = sanitize_string(input.name)
        if not name:
            raise ValueError("Category name cannot be empty")

        description = sanitize_string(input.description, max_length=1000) if input.description else None

        # Check for duplicate
        existing = db.query(CategoryModel).filter(CategoryModel.name == name).first()
        if existing:
            raise ValueError("A category with this name already exists")

        category = CategoryModel(name=name, description=description)
        db.add(category)
        db.commit()
        db.refresh(category)
        return Category(id=category.id, name=category.name, description=category.description)


# Schema with security extensions
# QueryDepthLimiter prevents deeply nested queries that could cause DoS
schema = Schema(
    query=Query,
    mutation=Mutation,
    extensions=[
        QueryDepthLimiter(max_depth=10),
    ],
)


# Custom GraphQL app with context
class SecureGraphQL(GraphQL):
    async def get_context(self, request, response=None):
        db = SessionLocal()
        return {"db": db, "request": request}

    async def process_result(self, request, result):
        # Clean up database session after request
        context = None
        try:
            context = await self.get_context(request)
        except Exception:
            pass
        response = await super().process_result(request, result)
        return response


def get_context():
    db = SessionLocal()
    try:
        return {"db": db}
    except Exception:
        db.close()
        raise


# Application factory
def create_app():
    graphql_app = SecureGraphQL(schema)

    # Restrict CORS to specific origins in production
    allowed_origins = os.environ.get("ALLOWED_ORIGINS", "http://localhost:3000").split(",")

    app = Starlette(
        middleware=[
            Middleware(
                CORSMiddleware,
                allow_origins=allowed_origins,
                allow_methods=["POST"],  # GraphQL only needs POST
                allow_headers=["Content-Type", "Authorization"],
                allow_credentials=False,
            ),
        ],
    )
    app.mount("/graphql", graphql_app)
    return app


